+  env?: NodeJS.ProcessEnv;
+}
+
+export class CommandError extends Error {
+  constructor(
+    message: string,
+    public readonly command: string,
+    public readonly args: string[],
+    public readonly code: number | string | null,
+    public readonly signal: NodeJS.Signals | null,
+    public readonly stdout: string,
+    public readonly stderr: string,
+    public readonly timedOut: boolean,
+  ) {
+    super(message);
+    this.name = 'CommandError';
+  }
+}

 /**
  * Runner utility for Shinobibot to execute system commands.
- * This is used to trigger the OpenGravity Kernel and other CLI tools.
+ * Uses execFile (no shell) with a bounded timeout to prevent hung children
+ * from causing denial-of-service. Errors are surfaced as structured
+ * CommandError instances carrying stdout/stderr/exit metadata.
  */
-export async function run_command(command: string, cwd: string = process.cwd()): Promise<string> {
+export async function run_command(
+  command: string,
+  args: string[] = [],
+  options: RunCommandOptions = {},
+): Promise<string> {
+  const { cwd = process.cwd(), timeoutMs = DEFAULT_TIMEOUT_MS, env } = options;
+  console.log(`[Runner] Executing: ${command} ${args.join(' ')} (timeout=${timeoutMs}ms)`);
   try {
-    console.log(`[Runner] Executing: ${command}`);
-    const output = execSync(command, { cwd, encoding: 'utf-8', stdio: 'pipe' });
-    return output;
+    const { stdout } = await execFileAsync(command, args, {
+      cwd,
+      env,
+      encoding: 'utf-8',
+      timeout: timeoutMs,
+      maxBuffer: 10 * 1024 * 1024,
+    });
+    return stdout;
   } catch (error: any) {
-    const stderr = error.stderr ? error.stderr.toString() : '';
-    const stdout = error.stdout ? error.stdout.toString() : '';
-    throw new Error(`Command failed: ${command}\nError: ${error.message}\nStdout: ${stdout}\nStderr: ${stderr}`);
+    const stdout = error?.stdout ? error.stdout.toString() : '';
+    const stderr = error?.stderr ? error.stderr.toString() : '';
+    const signal: NodeJS.Signals | null = error?.signal ?? null;
+    const code: number | string | null = error?.code ?? null;
+    const timedOut = signal === 'SIGTERM' && error?.killed === true;
+    const reason = timedOut
+      ? `timed out after ${timeoutMs}ms`
+      : error?.message ?? 'unknown error';
+    throw new CommandError(
+      `Command failed: ${command} ${args.join(' ')} (${reason})`,
+      command,
+      args,
+      code,
+      signal,
+      stdout,
+      stderr,
+      timedOut,
+    );
   }
 }

