+import { describe, it, expect, beforeEach, afterEach } from "vitest";
+import * as path from "path";
+import * as os from "os";
+import { validatePath } from "../utils/permissions";
+
+describe("validatePath", () => {
+  const prev = process.env.WORKSPACE_ROOT;
+
+  afterEach(() => {
+    if (prev === undefined) delete process.env.WORKSPACE_ROOT;
+    else process.env.WORKSPACE_ROOT = prev;
+  });
+
+  it("throws when WORKSPACE_ROOT is not set", () => {
+    delete process.env.WORKSPACE_ROOT;
+    expect(() => validatePath("foo.txt")).toThrow(/WORKSPACE_ROOT/);
+  });
+
+  it("throws when WORKSPACE_ROOT is empty", () => {
+    process.env.WORKSPACE_ROOT = "   ";
+    expect(() => validatePath("foo.txt")).toThrow(/WORKSPACE_ROOT/);
+  });
+
+  it("resolves a relative path inside the workspace", () => {
+    const root = path.resolve(os.tmpdir(), "shinobi-ws");
+    process.env.WORKSPACE_ROOT = root;
+    const out = validatePath("a/b.txt");
+    expect(out).toBe(path.resolve(root, "a/b.txt"));
+  });
+
+  it("rejects traversal outside the workspace", () => {
+    const root = path.resolve(os.tmpdir(), "shinobi-ws");
+    process.env.WORKSPACE_ROOT = root;
+    expect(() => validatePath("../escape.txt")).toThrow(/escapes workspace/);
+  });
+});

